Method.Source:
public static void main(Args args)
{
    var builder = DBMSQLQueryStoreQueryHintsViewBuilder::construct();
    builder.createSqlObjects();
}

private str createViewSqlStmt()
{
    str sqlStmt = 'CREATE VIEW ' + viewName + ' AS ' + this.createSQLStatement();
    return sqlStmt;
}

private str createSQLStatement()
{
    if (DBMSQLUtils::databaseCompatibilityLevel() >= 160)
    {
        return this.createSQLStatement2022();
    }
    else
    {
        return this.createSQLStatement2019();
    }
}

protected void initialize(boolean _runOnSeparateUserConnection = false)
{
    super(_runOnSeparateUserConnection);

    SysDictView view    = new SysDictView(tableNum(DBMSQLQueryStoreQueryHints));
    viewName            = view.name(DbBackend::Sql);
    asQueryHintId = view.fieldObject(fieldNum(DBMSQLQueryStoreQueryHints, QueryHintId)).name(DbBackend::Sql);
    asQueryId = view.fieldObject(fieldNum(DBMSQLQueryStoreQueryHints, QueryId)).name(DbBackend::Sql);
    asReplicaGroupId = view.fieldObject(fieldNum(DBMSQLQueryStoreQueryHints, ReplicaGroupId)).name(DbBackend::Sql);
    asQueryHintText = view.fieldObject(fieldNum(DBMSQLQueryStoreQueryHints, QueryHintText)).name(DbBackend::Sql);
    asLastQueryHintFailureReason = view.fieldObject(fieldNum(DBMSQLQueryStoreQueryHints, LastQueryHintFailureReason)).name(DbBackend::Sql);
    asLastQueryHintFailureReasonDesc = view.fieldObject(fieldNum(DBMSQLQueryStoreQueryHints, LastQueryHintFailureReasonDesc)).name(DbBackend::Sql);
    asQueryHintFailureCount = view.fieldObject(fieldNum(DBMSQLQueryStoreQueryHints, QueryHintFailureCount)).name(DbBackend::Sql);
    asSource = view.fieldObject(fieldNum(DBMSQLQueryStoreQueryHints, Source)).name(DbBackend::Sql);
    asSourceDesc = view.fieldObject(fieldNum(DBMSQLQueryStoreQueryHints, SourceDesc)).name(DbBackend::Sql);
    asComment = view.fieldObject(fieldNum(DBMSQLQueryStoreQueryHints, Comment)).name(DbBackend::Sql);
    asRecId = view.fieldObject(fieldNum(DBMSQLQueryStoreQueryHints, RecId)).name(DbBackend::Sql);
}

public static DBMSQLQueryStoreQueryHintsViewBuilder construct()
{
    return new DBMSQLQueryStoreQueryHintsViewBuilder();
}
